function solve(s) {
    let result = [];
    for (const c of s) {
        if (c >= 'a' && c <= 'z') {
            result.push(c);
        } else if (c === '*') {
            if (result.length > 0) {
                result.pop();
            }
        } else if (c === '#') {
            result = result.concat(result);
        } else if (c === '%') {
            result.reverse();
        }
    }
    return result.join('');
}
```

